<template>
  <div class="home-container">
    <div class="welcome-card">
      <div class="welcome-header">
        <h1>欢迎使用A2A工作流平台</h1>
      </div>
      <div class="welcome-content">
        <p>A2A工作流平台是一个强大的工作流自动化系统，设计用于编排和管理A2A（Agent-to-Agent）任务，实现多智能体协作和自动化处理。</p>
        <div class="cta-buttons">
          <button class="btn btn-primary" @click="goToLogin">登录</button>
          <button class="btn btn-success" @click="goToRegister">注册</button>
        </div>
      </div>
    </div>

    <el-row :gutter="20" class="feature-row" v-if="isAuthenticated">
      <el-col :xs="24" :sm="12" :md="8" :lg="6" v-for="(feature, index) in features" :key="index">
        <el-card class="feature-card">
          <div class="feature-icon">
            <el-icon :size="40"><component :is="feature.icon" /></el-icon>
          </div>
          <h3>{{ feature.title }}</h3>
          <p>{{ feature.description }}</p>
          <el-button type="primary" plain @click="$router.push(feature.link)">
            {{ feature.buttonText }}
          </el-button>
        </el-card>
      </el-col>
    </el-row>

    <el-row v-if="isAuthenticated && dashboardData">
      <el-col :span="24">
        <h2 class="dashboard-title">平台概览</h2>
      </el-col>
      <el-col :xs="24" :sm="12" :md="6">
        <el-card class="dashboard-card">
          <h4>工作流</h4>
          <div class="dashboard-number">{{ dashboardData.workflows || 0 }}</div>
        </el-card>
      </el-col>
      <el-col :xs="24" :sm="12" :md="6">
        <el-card class="dashboard-card">
          <h4>运行中实例</h4>
          <div class="dashboard-number">{{ dashboardData.runningInstances || 0 }}</div>
        </el-card>
      </el-col>
      <el-col :xs="24" :sm="12" :md="6">
        <el-card class="dashboard-card">
          <h4>智能体</h4>
          <div class="dashboard-number">{{ dashboardData.agents || 0 }}</div>
        </el-card>
      </el-col>
      <el-col :xs="24" :sm="12" :md="6">
        <el-card class="dashboard-card">
          <h4>任务</h4>
          <div class="dashboard-number">{{ dashboardData.tasks || 0 }}</div>
        </el-card>
      </el-col>
    </el-row>
  </div>
</template>

<script>
import { computed, onMounted, ref } from 'vue'
import { useAuthStore } from '../store/auth'
import axios from 'axios'
import {
  Connection, 
  Document, 
  Setting, 
  Monitor
} from '@element-plus/icons-vue'

export default {
  name: 'HomeView',
  components: {
    Connection,
    Document,
    Setting,
    Monitor
  },
  setup() {
    const authStore = useAuthStore()
    const isAuthenticated = computed(() => {
      const storeAuth = authStore.isAuthenticated;
      const localAuth = localStorage.getItem('authenticated') === 'true';
      console.log('Home页面 - 认证状态检查:', { 
        storeAuth, 
        localAuth, 
        user: authStore.user 
      });
      return storeAuth || localAuth;
    })
    const dashboardData = ref(null)
    
    // 功能卡片
    const features = [
      {
        title: '工作流管理',
        description: '创建、编辑和管理工作流定义',
        icon: 'Document',
        link: '/workflow',
        buttonText: '查看工作流'
      },
      {
        title: '工作流实例',
        description: '监控和管理工作流执行实例',
        icon: 'Monitor',
        link: '/workflow/instance',
        buttonText: '查看实例'
      },
      {
        title: '智能体管理',
        description: '配置和测试A2A协议智能体',
        icon: 'Connection',
        link: '/agents',
        buttonText: '管理智能体'
      },
      {
        title: '系统设置',
        description: '管理个人资料和系统配置',
        icon: 'Setting',
        link: '/profile',
        buttonText: '查看设置'
      }
    ]
    
    // 获取仪表盘数据
    const fetchDashboardData = async () => {
      if (!isAuthenticated.value) return
      
      try {
        // 添加延迟确保认证状态已经稳定
        await new Promise(resolve => setTimeout(resolve, 300))
        const response = await axios.get('/api/dashboard/')
        dashboardData.value = response.data
      } catch (error) {
        console.error('获取仪表盘数据失败', error)
        dashboardData.value = {
          workflows: 0,
          runningInstances: 0,
          agents: 0,
          tasks: 0
        }
      }
    }
    
    onMounted(() => {
      // 确保已经登录后再加载数据
      if (isAuthenticated.value) {
        fetchDashboardData()
      } else {
        // 如果未登录，添加一个延迟检查，可能认证状态会延迟更新
        setTimeout(() => {
          if (isAuthenticated.value) {
            fetchDashboardData()
          }
        }, 500)
      }
    })
    
    const goToLogin = () => {
      window.location.href = '/login'
    }
    
    const goToRegister = () => {
      window.location.href = '/register'
    }
    
    return {
      isAuthenticated,
      features,
      dashboardData,
      goToLogin,
      goToRegister
    }
  }
}
</script>

